import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function t(d,s){return n(),i("div",null,s[0]||(s[0]=[a(`<ol><li>更容易维护</li></ol><ul><li>组合式API</li><li>更好的TypeScript支持(底层也使用ts重写了)</li></ul><ol start="2"><li>更快的速度</li></ol><ul><li>重写diff算法</li><li>模版编译优化</li><li>更高效的组件初始化</li></ul><ol start="3"><li>更小的体积</li></ol><ul><li>良好的TreeShaking</li><li>按需引入</li></ul><ol start="4"><li>更优的数据响应式</li></ol><ul><li>Proxy</li></ul><ol start="5"><li>更新的构建工具 vue2使用的构建工具是vue-cli是基于webpack vue3使用的构建工具是create-vue是基于vite(下一代构建工具)的</li></ol><h1 id="开始" tabindex="-1"><a class="header-anchor" href="#开始"><span>开始</span></a></h1><p>要创建vue3项目必须使用16版本以上的node</p><ol><li>创建项目</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm init vue@latest</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>启动项目</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm run dev</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>在vue3中标签顺序也变化了,以script,template,style标签的顺序 在script标签中加上setup属性允许在script标签中声明组合式api 导入组件也无需再注册了 template标签中的根标签可以有多个</p><p>mount设置挂载点 <code>#app</code>id为app的盒子</p><div class="language-main.js line-numbers-mode" data-highlighter="shiki" data-ext="main.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>createApp(App).mount(&#39;#app&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="组合式api" tabindex="-1"><a class="header-anchor" href="#组合式api"><span>组合式api</span></a></h1><h3 id="setup" tabindex="-1"><a class="header-anchor" href="#setup"><span>setup</span></a></h3><p>组合式api的入口</p><ol><li>setup的执行时机比beforeCreate更早,因此再setup函数中获取不到this因为当时this还未创建是undefined</li><li>setup中的数据或函数需要return出去才能被使用</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default{</span></span>
<span class="line"><span>	setup(){</span></span>
<span class="line"><span>		const str=&#39;aeolian&#39;</span></span>
<span class="line"><span>		function test(){}</span></span>
<span class="line"><span>		return {</span></span>
<span class="line"><span>			str,</span></span>
<span class="line"><span>			test</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;div @click=&quot;test&quot;&gt;{{ str }}&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>简化写法</strong> 数据和函数再setup中return还是过于复杂,为了简化结构可以给script标签加上setup属性,加上setup属性后这个script标签内都是setup的作用范围,在里面定义的数据和函数不用显式return底层会自动地return</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;script setup&gt;</span></span>
<span class="line"><span>	const str=&#39;aeolian&#39;</span></span>
<span class="line"><span>	function test(){}</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="reactive" tabindex="-1"><a class="header-anchor" href="#reactive"><span>reactive</span></a></h3><p>接受对象类型数据的参数传入并返回一个响应式的对象 它定义在vue包中,需要按需导入</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const state = reactive({</span></span>
<span class="line"><span>	count:100</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>const setCount=()=&gt;{</span></span>
<span class="line"><span>	state.count++</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;div&gt;{{ state.count }}&lt;/div&gt;</span></span>
<span class="line"><span>&lt;button @click=&quot;setCount&quot;&gt;+l&lt;/button&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>reactive通常用于接收复杂的类型</p><h3 id="ref" tabindex="-1"><a class="header-anchor" href="#ref"><span>ref</span></a></h3><p>接收简单类型或者对象类型的数据专入并返回一个响应式的对象 也需要从vue包中按需导入</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const count=ref(0)</span></span>
<span class="line"><span>console.log(count.value)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>底层是在传入的数据基础上包装了一个对象成为了复杂类型,然后再借助reactive实现响应式,要访问数据需要通过.value 但是在template中获取数据不需要.value</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div&gt;{{ count }}&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="computed" tabindex="-1"><a class="header-anchor" href="#computed"><span>computed</span></a></h3><p>computed计算属性优化了写法 只需要将计算属性的逻辑函数传入到computed函数中再赋值给变量就可直接使用变量名获取</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const list=ref([1,2,3,4])</span></span>
<span class="line"><span>const computedList=computed(()=&gt;{</span></span>
<span class="line"><span>	return list.value.filter(item=&gt;item&gt;2)</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="watch" tabindex="-1"><a class="header-anchor" href="#watch"><span>watch</span></a></h3><p>监听一个或多个数据的变化,数据变化时执行传入的函数</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//监听一个数据</span></span>
<span class="line"><span>watch(count,(newValue,oldValue)=&gt;{})</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//监听多个数据并设置刷新页面立即执行</span></span>
<span class="line"><span>watch([count1,count2],(newArr,oldArr)=&gt;{},{immediate:true})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>一次性监听多个数据时传入的参数就是新数据数组和旧数据数组,哪个值改变都会调用该传入的函数 <strong>深度监视</strong> 默认是浅层监视,这样只能监视简单数据类型,复杂数据类型监视的是地址,也就是说复杂数据类型只有改变指向时才会被监视到 在选项中加入<code>deep:true</code>开启深度监视 深度监视可以监视到复杂数据类型中数据的变化</p><p><strong>只监视复杂数据类型中的其中一个数据</strong> 只监视对象中的一个数据就需要特定写法了</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>watch(</span></span>
<span class="line"><span>	()=&gt;user.age,</span></span>
<span class="line"><span>	()=&gt;console.log(&#39;用户的年龄变化了&#39;)</span></span>
<span class="line"><span>)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="生命周期函数" tabindex="-1"><a class="header-anchor" href="#生命周期函数"><span>生命周期函数</span></a></h1><table><thead><tr><th>选项式API</th><th>组合式API</th></tr></thead><tbody><tr><td>beforeCreate/created</td><td>setup</td></tr><tr><td>beforeMount</td><td>onBeforeMount</td></tr><tr><td>mounted</td><td>onMounted</td></tr><tr><td>beforeUpdate</td><td>onBeforeUpdate</td></tr><tr><td>updated</td><td>onUpdated</td></tr><tr><td>beforeUnmount</td><td>onBeforeUnmount</td></tr><tr><td>unmounted</td><td>onUnmounted</td></tr><tr><td>在vue3中也可以使用vue2中的选项式api</td><td></td></tr><tr><td>选项式api只能定义一个函数</td><td></td></tr><tr><td>组合式api可以定义多个函数,按照定义的顺序执行</td><td></td></tr></tbody></table><h1 id="父子间数据传递" tabindex="-1"><a class="header-anchor" href="#父子间数据传递"><span>父子间数据传递</span></a></h1><h3 id="props" tabindex="-1"><a class="header-anchor" href="#props"><span>props</span></a></h3><p>script标签中加上setup属性后就无法再使用vue2中的props属性了 可以使用编译器宏 父传子的方式不变,在子组件中接收数据使用编译器宏<code>defineProps</code></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const props = defineProps({</span></span>
<span class="line"><span>	car:String,</span></span>
<span class="line"><span>	money: Number</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="emit" tabindex="-1"><a class="header-anchor" href="#emit"><span>emit</span></a></h3><p>子传父的过程变化不大 在子组件中调用emit传递</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const buy=（）=&gt;{</span></span>
<span class="line"><span>	emit（&#39;changeMoney&#39;，5)</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="跨层级传递数据" tabindex="-1"><a class="header-anchor" href="#跨层级传递数据"><span>跨层级传递数据</span></a></h2><h3 id="provide和inject" tabindex="-1"><a class="header-anchor" href="#provide和inject"><span>provide和inject</span></a></h3><p>在vue3中provide和inject使用更加方便</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>// 顶层组件</span></span>
<span class="line"><span>provide(&#39;key&#39;,数据)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 底层组件</span></span>
<span class="line"><span>const message=inject(&#39;key&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>也可以传递函数</p><h1 id="模板引用" tabindex="-1"><a class="header-anchor" href="#模板引用"><span>模板引用</span></a></h1><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const testRef =ref(null)</span></span>
<span class="line"><span>const getCom =() =&gt;{</span></span>
<span class="line"><span>	console.log(testRef.value)</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;TestCom ref=&quot;testRef&quot;&gt;&lt;/TestCom&gt;</span></span>
<span class="line"><span>&lt;button@click=&quot;getCom&quot;&gt;获取组件&lt;/button&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>通过ref属性和ref函数配合获取dom对象</p><p>默认情况下在&lt;script setup&gt;下组件内部的属性和方法是不开放给父组件访问的 可以通过defineExpose编译宏指定哪些属性和方法允许访问</p><h1 id="defineoptins" tabindex="-1"><a class="header-anchor" href="#defineoptins"><span>defineOptins</span></a></h1><p>在3.3版本引入的 使用了<code>&lt;script setup&gt;</code>标签后无法使用评级属性引入了defineSetup和defineEmits宏,但使用依旧麻烦,且只有这两个宏</p><p>所以在Vue3.3中新引l入了defineOptions宏。顾名思义，主要是用来定义OptionsAPI的选项。可以用defineOptions定义任意的选项，props,emits,expose,slots除外（因为这些可以使用defineXXX来做到）</p><h1 id="definemodel" tabindex="-1"><a class="header-anchor" href="#definemodel"><span>defineModel</span></a></h1><p>在vue2中v-model相当于@和:value组合 在vue3中v-model相当于@和update:modelValue组合</p><p>因为是实验性质的所以使用时需要在vite中开启</p><div class="language-vite.config.js line-numbers-mode" data-highlighter="shiki" data-ext="vite.config.js" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>plugins:[</span></span>
<span class="line"><span>	vue({</span></span>
<span class="line"><span>		script:{</span></span>
<span class="line"><span>			defineModel:true</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	})</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用defineModel绑定的数据在子组件中也可以修改绑定的父组件的值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const modelValue=defineModel()</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;input type=&quot;text&quot; :value=&quot;modelValue&quot; @input=&quot;e=&gt;modelValue=e.target.value&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="pinia" tabindex="-1"><a class="header-anchor" href="#pinia"><span>pinia</span></a></h1><p>Pinia是Vue的最新状态管理工具，是Vuex的替代品</p><ol><li>提供更加简单的APl（去掉了mutation和modules）</li><li>提供符合，组合式风格的API（和Vue3新语法统一）</li><li>去掉了modules的概念，每一个store都是一个独立的模块</li><li>配合TypeScript更加友好，提供可靠的类型推断</li></ol><h2 id="使用" tabindex="-1"><a class="header-anchor" href="#使用"><span>使用</span></a></h2><ol><li>下载pinia</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm install pinia</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="2"><li>导入pinia</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import {createPinia} from &#39;pinia&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="3"><li>创建pinia实例</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const pinia=createPinia()</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ol start="4"><li>注册根实例</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>createApp(App).use(pinia)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="使用-1" tabindex="-1"><a class="header-anchor" href="#使用-1"><span>使用</span></a></h2><p>使用definestore定义store 定义store并提供数据 在store中要定义getters需要借助computed action中异步函数的写法和普通函数中写法一样</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export const useCounterStore = defineStore(&#39;count&#39;,()=&gt;{</span></span>
<span class="line"><span>	//声明数据 state-count</span></span>
<span class="line"><span>	const count = ref(θ)</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	//声明操作数据的方法action（普通函数）</span></span>
<span class="line"><span>	const addCount=()=&gt; count.value++</span></span>
<span class="line"><span>	const subCount=()=&gt; count.value--</span></span>
<span class="line"><span>	//action异步函数的写法</span></span>
<span class="line"><span>	async test(){</span></span>
<span class="line"><span>		const res=await axios.get(&#39;url&#39;)</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	</span></span>
<span class="line"><span>	//声明基于数据派生的计算属性getters（computed）</span></span>
<span class="line"><span>	const double=computed(() =&gt; count.value *2）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>	//声明数据state-msg</span></span>
<span class="line"><span>	const msg = ref(&#39;hello pinia&#39;)</span></span>
<span class="line"><span>	return {</span></span>
<span class="line"><span>		count,</span></span>
<span class="line"><span>		double,</span></span>
<span class="line"><span>		addCount,</span></span>
<span class="line"><span>		subCount</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>使用数据 导入store后要使用直接像对象那样调用里面的函数或者使用里面的值</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import {useCounterStore} from &#39;@/store/counte&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;div&gt;{{useCounterStore().count}&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用store中的数据时应不使用解构,如果使用解构会丢失数据的响应式</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const {count,msg}=counterStore</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>此时再对store中的数据进行更改就不会同步到store中了 因为store式用reactive包装的对象,reactive是使用对象包装的,只要对象存在就是响应式的,而解构是将数值拷贝给解构时创建的对象,和原reactive对象的数据没有关联</p><p>要让解构赋值数据支持响应式可以使用<code>storeToRegs</code></p><h2 id="持久化插件" tabindex="-1"><a class="header-anchor" href="#持久化插件"><span>持久化插件</span></a></h2><p>导入并使用</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>import persist from &#39;pinia-plugin-persistedstate&#39;</span></span>
<span class="line"><span>createApp(App).use(pinia.use(persist))</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>开启模块的持久化 在选项中开启<code>persist:true</code></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export const useCounterStore = defineStore(&#39;count&#39;,()=&gt;{},{persist:true})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果要使用自定义键名可以在<code>persist</code>下指定</p>`,97)]))}const r=e(l,[["render",t]]),c=JSON.parse('{"path":"/front/vue/6/","title":"6 vue3","lang":"zh-CN","frontmatter":{"title":"6 vue3","createTime":"2025/05/06 22:01:42","permalink":"/front/vue/6/"},"readingTime":{"minutes":6.34,"words":1903},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/vue/6 vue3.md","headers":[]}');export{r as comp,c as data};
